#include<bits/stdc++.h>
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI m=5e5*3+5;
int n,a[m],l[m],r[m],c[m],s1[m][20],s2[m][20];
int qp(int a,int b)
{
	int res=1;
	wh(b)
	{
		if(b&1)res=res*a;
		a=a*a;
		b>>=1;
	}
	return res;
}
void bd()
{
	FOR(i,1,3*n)
	{
		s1[i][0]=2*i-l[i];
		s2[i][0]=r[i]-2*i;
	}
	FOR(j,1,20)
	{
		FOR(i,1,3*n-(1<<j)+1)
		{
			s1[i][j]=min(s1[i][j-1],s1[i+(1<<(j-1))][j-1]);
			s2[i][j]=min(s2[i][j-1],s2[i+(1<<(j-1))][j-1]);
		}
	}
}
int qry(int x,int y,int s[][20])
{
	int len=y-x+1;
	int k=log2(len);
	return min(s[x][k],s[y-(1<<k)+1][k]);
}
signed main()
{
	IOS
	cin>>n;
	FOR(i,1,n)
	{
		cin>>a[i+n];
		a[i]=a[i+n];
		a[i+2*n]=a[i+n];
	}
	int p=1;
	FOR(i,1,3*n)
	{
		c[a[i]]++;
		wh(c[a[p]]>1)
		{
			c[a[p]]--;
			p++;
		}
		l[i]=p;
	}
	memset(c,0,sizeof(c));
	int q=3*n;
	ROF(i,3*n,1)
	{
		c[a[i]]++;
		wh(c[a[q]]>1)
		{
			c[a[q]]--;
			q--;
		}
		r[i]=q;
	}
	bd();
	FOR(i,n+1,2*n)
	{
		int t1=i-l[i];
		int t2=r[i]-i;
		int t3=i+qry(l[i]+1,i,s2);
		int t4=qry(i,r[i]-1,s1)-i;
		cout<<min(min(t2,t1),min(t3,t4))<<" ";
	}
	return 0;
}
